
package com.example.taxgap.service; import com.example.taxgap.domain.entity.FinancialTransaction; import com.example.taxgap.domain.enums.*; import org.springframework.stereotype.Service; import java.math.*;
@Service public class TaxComputationService { private final AuditLogService audit; public TaxComputationService(AuditLogService audit){this.audit=audit;} public void compute(FinancialTransaction ft){ BigDecimal expected=ft.getAmount().multiply(ft.getTaxRate()).setScale(2, RoundingMode.HALF_UP); ft.setExpectedTax(expected); if(ft.getReportedTax()==null){ ft.setComplianceStatus(ComplianceStatus.NON_COMPLIANT); audit.log(EventType.TAX_COMPUTATION, ft.getTransactionId(), "reportedTax missing => NON_COMPLIANT"); return; } BigDecimal gap=expected.subtract(ft.getReportedTax()).setScale(2, RoundingMode.HALF_UP); ft.setTaxGap(gap); int cmp=gap.abs().compareTo(new BigDecimal("1.00")); if(cmp<=0) ft.setComplianceStatus(ComplianceStatus.COMPLIANT); else if(gap.compareTo(BigDecimal.ZERO)>0) ft.setComplianceStatus(ComplianceStatus.UNDERPAID); else ft.setComplianceStatus(ComplianceStatus.OVERPAID); audit.log(EventType.TAX_COMPUTATION, ft.getTransactionId(), String.format("expected=%s reported=%s gap=%s status=%s", expected, ft.getReportedTax(), gap, ft.getComplianceStatus())); } }
